// Helper function to check if host is localhost or loopback address
func isLocalhost(host string) bool {
	if host == "" {
		return false
	}
	hostname, _, err := net.SplitHostPort(host)
	if err != nil {
		hostname = host // if no port, use the whole host
	}
	return hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" || strings.HasSuffix(hostname, ".localhost")
}

// Helper function to check if domain is allowed
func isAllowedDomain(hostname string, allowedDomains []string) bool {
	// Always allow localhost for development/testing
	if isLocalhost(hostname) {
		return true
	}
	for _, domain := range allowedDomains {
		if hostname == domain || (len(hostname) > len(domain) && hostname[len(hostname)-len(domain)-1:] == "."+domain) {
			return true
		}
	}
	return false
}

// Helper function to validate path safety
func isSafePath(path string) bool {
	// Prevent directory traversal and other unsafe patterns
	unsafePatterns := []string{"..", "//", "./", "\\"}
	for _, pattern := range unsafePatterns {
		if contains(path, pattern) {
			return false
		}
	}
	return true
}

// Helper function to check if string contains substring
func contains(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(s) > len(substr) && (s[:len(substr)] == substr || contains(s[1:], substr)))
}

// Helper function to generate CSRF token
func generateCSRFToken() string {
	tokenBytes := make([]byte, 32)
	if _, err := rand.Read(tokenBytes); err != nil {
		return ""
	}
	return base64.URLEncoding.EncodeToString(tokenBytes)
}

