	redirectURL, err := buildRedirectURL(r, redirectPath)
	if err != nil {
		return "", fmt.Errorf("failed to build redirect URL: %w", err)
	}

	// Create a config copy with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate the authorization URL with state parameter
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOffline)

	return authURL, nil
}

