func generateRandomState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// buildRedirectURL constructs the full redirect URL from request and path
func buildRedirectURL(r *http.Request, path string) (string, error) {
	// Determine scheme (http or https)
	scheme := "http"
	if r.TLS != nil || r.Header.Get("X-Forwarded-Proto") == "https" {
		scheme = "https"
	}

	// Use the request's host
	host := r.Host
	if host == "" {
		host = "localhost:8080" // Default fallback
	}

	// Construct the full URL
	u := &url.URL{
		Scheme: scheme,
		Host:   host,
		Path:   path,
	}

	return u.String(), nil
}

