// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate inputs
	if redirectPath == "" {
		return "", errors.New("redirect path cannot be empty")
	}
	if session == nil {
		return "", errors.New("session cookie cannot be nil")
	}

	// Generate a secure random state parameter
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", err
	}
	state := base64.URLEncoding.EncodeToString(stateBytes)

	// Store the state and redirect path in the session
	sessionData := map[string]interface{}{
		"state":         state,
		"redirect_path": redirectPath,
		"timestamp":     time.Now().Unix(),
	}

	jsonData, err := json.Marshal(sessionData)
	if err != nil {
		return "", err
	}

	// Update session cookie with the state data
	session.Value = base64.URLEncoding.EncodeToString(jsonData)
	session.Path = "/"
	session.HttpOnly = true
	session.Secure = true // Use Secure in production (HTTPS)
	session.SameSite = http.SameSiteLaxMode
	session.MaxAge = 300 // 5 minutes expiration

	// Set the cookie in the response
	http.SetCookie(w, session)

	// Create a temporary config with the custom redirect URL
	tempConfig := &oauth2.Config{
		ClientID:     OAuthConfig.ClientID,
		ClientSecret: OAuthConfig.ClientSecret,
		RedirectURL:  "https://yourapp.com" + redirectPath,
		Scopes:       OAuthConfig.Scopes,
		Endpoint:     OAuthConfig.Endpoint,
	}

	// Generate the authorization URL with state parameter
	authURL := tempConfig.AuthCodeURL(state,
		oauth2.SetAuthURLParam("response_type", "code"),
		oauth2.SetAuthURLParam("access_type", "offline"),
	)

	return authURL, nil
}

// Optional: Helper function to validate state from session
func ValidateState(session *http.Cookie, expectedState string) (string, error) {
	if session == nil || session.Value == "" {
		return "", errors.New("invalid session")
	}

	// Decode session value
	decoded, err := base64.URLEncoding.DecodeString(session.Value)
	if err != nil {
		return "", err
	}

	// Parse session data
	var sessionData map[string]interface{}
	if err := json.Unmarshal(decoded, &sessionData); err != nil {
		return "", err
	}

	// Check if state matches
	storedState, ok := sessionData["state"].(string)
	if !ok || storedState != expectedState {
		return "", errors.New("state mismatch")
	}

	// Check expiration (5 minutes)
	timestamp, ok := sessionData["timestamp"].(float64)
	if !ok || time.Since(time.Unix(int64(timestamp), 0)) > 5*time.Minute {
		return "", errors.New("session expired")
	}

	// Return the stored redirect path
	redirectPath, _ := sessionData["redirect_path"].(string)
	return redirectPath, nil
}

